```tsx
import React, { useState, useEffect } from 'react';
import { 
  AlertCircle, 
  Sparkles, 
  ChevronDown, 
  AlertTriangle, 
  CheckCircle,
  Stethoscope,
  Activity,
  FileText,
  Leaf,
  Navigation,
  ClipboardList,
  ClipboardCheck,
  ArrowRight,
  Volume2,
  StopCircle,
  FileDown
} from 'lucide-react';
import { Language, PatientData } from '../types';
import { jsPDF } from 'jspdf';

interface AnalysisResultProps {
  markdown: string;
  language?: Language;
  patientData?: PatientData;
}

interface Section {
  title: string;
  content: string[];
  icon: React.ReactNode;
}

const AnalysisResult: React.FC<AnalysisResultProps> = ({ markdown, language, patientData }) => {
  // Default all sections to collapsed (false)
  const [expandedSections, setExpandedSections] = useState<Record<number, boolean>>({});
  const [isSpeaking, setIsSpeaking] = useState(false);
  const [canSpeak, setCanSpeak] = useState(false);

  useEffect(() => {
    if (typeof window !== 'undefined' && window.speechSynthesis) {
      setCanSpeak(true);
      window.speechSynthesis.getVoices();
    }

    return () => {
      if (window.speechSynthesis) {
        window.speechSynthesis.cancel();
      }
    };
  }, []);

  // Helper to clean title strings (remove markdown, numbers, emojis)
  const cleanSectionTitle = (raw: string) => {
    return raw
      .replace(/^[#\d\.\s\*]+/, '') // Remove leading markdown/#/numbers
      .replace(/[\*:]+$/g, '')      // Remove trailing chars
      .replace(/👨‍⚕️|🩺|⚠️|📋|🚨|🔍|📄|🌿|✅|🧭/g, '') // Remove prompt-specific emojis
      .replace(/[\u{1F300}-\u{1F9FF}\u{2600}-\u{26FF}\u{2700}-\u{27BF}]/gu, '') // Generic emoji ranges
      .trim();
  };

  const cleanText = (text: string) => text
    .replace(/\*\*/g, '')           // Remove bold
    .replace(/__/g, '')             // Remove italics
    .replace(/\[.*?\]\(.*?\)/g, '') // Remove links
    .replace(/^\s*[-*•]\s+/gm, '• ') // Normalize bullets
    .trim();

  // Parse Markdown into Sections
  const parseMarkdown = (text: string): Section[] => {
    const lines = text.split('\n');
    const sections: Section[] = [];
    let currentSection: Section | null = null;

    const getIconForTitle = (title: string) => {
      const lower = title.toLowerCase();
      if (lower.includes('safety')) return <AlertCircle className="text-red-500" />;
      if (lower.includes('summary')) return <ClipboardList className="text-blue-500" />;
      if (lower.includes('triage') || lower.includes('urgency')) return <AlertTriangle className="text-orange-500" />;
      if (lower.includes('explanation') || lower.includes('differential')) return <Stethoscope className="text-teal-500" />;
      if (lower.includes('report') || lower.includes('lab')) return <FileText className="text-purple-500" />;
      if (lower.includes('ayurveda') || lower.includes('ayurvedic')) return <Leaf className="text-green-500" />;
      if (lower.includes('next') || lower.includes('can do')) return <Navigation className="text-indigo-500" />;
      if (lower.includes('doctor') || lower.includes('handover')) return <ClipboardCheck className="text-slate-600" />;
      return <Activity className="text-slate-500" />;
    };

    lines.forEach((line) => {
      // Detect Headers: #, ##, or 1. Title, or **Title**
      const headerMatch = line.match(/^((#+\s)|(\d+\.\s))?(\*\*)?(.+?)(\*\*)?(:)?$/);
      const isHeaderCandidate = (line.startsWith('#') || line.match(/^\d+\.\s/)) && line.length < 100;
      const isBoldTitle = line.startsWith('**') && line.endsWith('**') && line.length < 80 && !line.includes('.');

      if ((isHeaderCandidate || isBoldTitle) && line.trim().length > 3) {
        if (currentSection) {
          sections.push(currentSection);
        }

        const rawTitle = line.replace(/\*\*/g, '').trim();
        const title = cleanSectionTitle(rawTitle);

        currentSection = {
          title: title,
          content: [],
          icon: getIconForTitle(title)
        };
      } else if (currentSection) {
        currentSection.content.push(line);
      }
    });

    if (currentSection) {
      sections.push(currentSection);
    }

    // Fallback if parsing failed
    if (sections.length === 0) {
       sections.push({ title: "Analysis Output", content: lines, icon: <Sparkles className="text-teal-500" /> });
    }

    return sections;
  };

  const sections = parseMarkdown(markdown);

  // Extract Triage Level for UI Logic (Colors)
  // We still use English keywords for internal UI logic (banners) because logic is code-side.
  // Visual text comes from Gemini.
  const getTriageLevel = () => {
    // Find section by content keywords if title is localized
    const fullText = markdown.toLowerCase();
    if (fullText.includes('emergency') || fullText.includes('immediate care')) return 'emergency';
    if (fullText.includes('doctor soon') || fullText.includes('see a doctor') || fullText.includes('urgent')) return 'urgent';
    if (fullText.includes('mild') || fullText.includes('self-care')) return 'mild';
    return 'unknown';
  };

  const triageLevel = getTriageLevel();

  // Identify Sections
  const summarySection = sections.find(s => s.title.toLowerCase().includes('summary') && !s.title.toLowerCase().includes('handover'));
  const nextStepsSection = sections.find(s => s.title.toLowerCase().includes('next') || s.title.toLowerCase().includes('can do'));
  const doctorSection = sections.find(s => s.title.toLowerCase().includes('doctor') || s.title.toLowerCase().includes('handover'));
  const triageSection = sections.find(s => s.title.toLowerCase().includes('triage') || s.title.toLowerCase().includes('urgency'));

  // Filter sections for the bottom accordion (exclude Triage and Safety as they are highlighted elsewhere if desired, 
  // but let's keep Safety in accordion for reference, and Triage is in banner)
  const accordionSections = sections.filter(s => {
      const t = s.title.toLowerCase();
      // We show Triage in the banner, so hide it from accordion to reduce redundancy? 
      // User asked to "Keep all other sections... as collapsible". Let's keep them all except maybe duplicate summary.
      // Actually, let's keep all for completeness in the accordion list.
      return true; 
  });

  // Extract Quick View Data
  const getQuickActions = () => {
      if (!nextStepsSection) return [];
      return nextStepsSection.content
        .filter(line => line.trim().match(/^[-*]|\d+\./)) // Bullet points
        .slice(0, 3)
        .map(line => line.replace(/^[-*]|\d+\.\s*/, '').replace(/\*\*/g, '').trim());
  };
  const quickActions = getQuickActions();

  const getSummarySnippet = () => {
      if (!summarySection) return null;
      const line = summarySection.content.find(l => l.trim().length > 0 && !l.trim().startsWith('-'));
      return line ? line.replace(/\*\*/g, '') : "View full summary below.";
  };
  const summarySnippet = getSummarySnippet();

  const toggleSection = (index: number) => {
    setExpandedSections(prev => ({ ...prev, [index]: !prev[index] }));
  };

  // Helper to map UI language to BCP-47 codes
  const mapLanguageToBCP47 = (lang: string | undefined): string => {
    switch (lang) {
      case 'Hindi': return 'hi-IN';
      case 'Kannada': return 'kn-IN';
      case 'Telugu': return 'te-IN';
      case 'Tamil': return 'ta-IN';
      case 'Marathi': return 'mr-IN';
      case 'Bengali': return 'bn-IN';
      case 'Gujarati': return 'gu-IN';
      case 'Malayalam': return 'ml-IN';
      case 'Odia': return 'or-IN';
      case 'English': return 'en-US';
      default: return 'auto';
    }
  };

  // Improved Speakable Text Extraction
  // Uses the actual content from the model (which is in the preferred language)
  const extractSpeakableText = (): string => {
    let textParts: string[] = [];

    // 1. Triage Section (Title + Content)
    if (triageSection) {
       textParts.push(cleanText(triageSection.title) + ".");
       textParts.push(cleanText(triageSection.content.join('. ')));
    }

    // 2. Summary Section (Title + Content)
    if (summarySection) {
      textParts.push(cleanText(summarySection.title) + ".");
      textParts.push(cleanText(summarySection.content.join('. ')));
    }

    // 3. Next Steps (Title + Bullets only)
    if (nextStepsSection) {
      textParts.push(cleanText(nextStepsSection.title) + ".");
      const bullets = nextStepsSection.content.filter(line => line.trim().match(/^[-*]|\d+\./));
      if (bullets.length > 0) {
        textParts.push(cleanText(bullets.join('. ')));
      }
    }

    // If no specific sections found, fallback to snippet
    if (textParts.length === 0 && summarySnippet) {
        return summarySnippet;
    }

    return textParts.join('. ').replace(/\.\./g, '.');
  };

  const handleSpeak = () => {
    if (!canSpeak) return;
    window.speechSynthesis.cancel();

    const speakableText = extractSpeakableText();
    const utterance = new SpeechSynthesisUtterance(speakableText);

    const langCode = mapLanguageToBCP47(language?.toString());
    if (langCode !== 'auto') {
      utterance.lang = langCode;
    }

    utterance.onstart = () => setIsSpeaking(true);
    utterance.onend = () => setIsSpeaking(false);
    utterance.onerror = () => setIsSpeaking(false);

    window.speechSynthesis.speak(utterance);
  };

  const handleStop = () => {
    if (window.speechSynthesis) {
      window.speechSynthesis.cancel();
      setIsSpeaking(false);
    }
  };

  // Improved PDF Generation
  const handleDownloadPDF = () => {
    try {
      const doc = new jsPDF();
      const pageWidth = doc.internal.pageSize.getWidth();
      const margin = 15;
      const contentWidth = pageWidth - (margin * 2);
      let yPos = 20;

      // Title
      doc.setFontSize(18);
      doc.setTextColor(13, 148, 136); // Teal color
      doc.text("MediAI – Health Triage Report", margin, yPos);
      yPos += 8;

      // Date
      doc.setFontSize(10);
      doc.setTextColor(100);
      doc.text(`Generated: ${new Date().toLocaleString()}`, margin, yPos);
      yPos += 12;

      // Patient Basics
      if (patientData) {
        doc.setFontSize(11);
        doc.setTextColor(0);
        doc.setFont("helvetica", "bold");
        doc.text("Patient Basics:", margin, yPos);
        yPos += 6;

        doc.setFont("helvetica", "normal");
        const basics = [
          `Age/Sex: ${patientData.age}, ${patientData.sex}`,
          `Duration: ${patientData.duration}`,
          `Conditions: ${patientData.conditions || "None"}`,
          `Medications: ${patientData.medications || "None"}`
        ];

        basics.forEach(line => {
          doc.text(line, margin + 5, yPos);
          yPos += 6;
        });
        yPos += 6;
      }

      // Helper to add section to PDF
      const addSectionToPDF = (title: string, contentLines: string[]) => {
        if (!contentLines || contentLines.length === 0) return;
        const content = cleanText(contentLines.join('\n'));

        // Check for page break
        if (yPos > 250) {
          doc.addPage();
          yPos = 20;
        }

        doc.setFontSize(12);
        doc.setTextColor(0);
        doc.setFont("helvetica", "bold");
        doc.text(title, margin, yPos);
        yPos += 7;

        doc.setFontSize(10);
        doc.setFont("helvetica", "normal");
        const splitText = doc.splitTextToSize(content, contentWidth);
        doc.text(splitText, margin, yPos);
        yPos += (splitText.length * 5) + 8;
      };

      // 1. Triage Section (Full Content)
      if (triageSection) {
          addSectionToPDF("Triage Analysis", triageSection.content);
      } else {
          // Fallback if section not found by regex
          const triageText = triageLevel === 'emergency' ? 'EMERGENCY - Seek Immediate Care' :
                         triageLevel === 'urgent' ? 'See Doctor Soon - Medical Attention Advised' :
                         triageLevel === 'mild' ? 'Likely Mild - Self-Care Sufficient' : 'Analysis Completed';
          addSectionToPDF("Triage Status", [triageText]);
      }

      // 2. Summary Section (Full Content)
      if (summarySection) {
          addSectionToPDF("Summary of Understanding", summarySection.content);
      }

      // 3. Recommended Actions (Full Content)
      if (nextStepsSection) {
          addSectionToPDF("Recommended Actions", nextStepsSection.content);
      }

      // 4. Doctor Handover (Full Content)
      if (doctorSection) {
          addSectionToPDF("Doctor Handover Summary", doctorSection.content);
      }

      // 5. Warning
      if (language && language !== 'English' && language !== 'Auto') {
          doc.setFontSize(8);
          doc.setTextColor(150);
          doc.text("* Note: Some local language characters may not render correctly in this standard PDF font.", margin, 280);
      }

      doc.save("MediAI-report.pdf");

    } catch (error) {
      console.error("PDF Generation Error:", error);
      alert("Could not generate PDF. Please try again.");
    }
  };

  const renderContent = (lines: string[]) => {
    return lines.map((line, i) => {
      if (line.trim() === '') return <div key={i} className="h-2"></div>;

      const parts = line.split(/(\*\*.*?\*\*)/g);
      const parsedLine = parts.map((part, idx) => {
        if (part.startsWith('**') && part.endsWith('**')) {
          return <strong key={idx} className="font-semibold text-slate-900">{part.slice(2, -2)}</strong>;
        }
        return part;
      });

      if (line.trim().startsWith('- ') || line.trim().startsWith('* ')) {
        return (
          <div key={i} className="flex items-start ml-2 mb-1.5">
            <span className="mr-2 mt-1.5 w-1.5 h-1.5 bg-slate-400 rounded-full flex-shrink-0"></span>
            <span className="text-slate-700 leading-relaxed">{parsedLine}</span>
          </div>
        );
      }

      return <p key={i} className="text-slate-700 leading-relaxed mb-2">{parsedLine}</p>;
    });
  };

  return (
    <div className="space-y-4 animate-in fade-in slide-in-from-bottom-4 duration-700">

      {/* QUICK VIEW CARD */}
      <div className={`rounded-2xl border shadow-sm overflow-hidden transition-all duration-500
        ${triageLevel === 'emergency' ? 'bg-red-50 border-red-200' : 
          triageLevel === 'urgent' ? 'bg-orange-50 border-orange-200' :
          triageLevel === 'mild' ? 'bg-green-50 border-green-200' :
          'bg-white border-slate-200'}`}>

        {/* Header / Banner */}
        <div className={`p-5 flex items-start justify-between gap-4 border-b 
            ${triageLevel === 'emergency' ? 'border-red-100/50' : 
              triageLevel === 'urgent' ? 'border-orange-100/50' :
              triageLevel === 'mild' ? 'border-green-100/50' :
              'border-slate-100'}`}>

          <div className="flex items-start gap-4">
            <div className={`p-2 rounded-full flex-shrink-0 
              ${triageLevel === 'emergency' ? 'bg-red-200 text-red-700' : 
                triageLevel === 'urgent' ? 'bg-orange-200 text-orange-700' :
                triageLevel === 'mild' ? 'bg-green-200 text-green-700' :
                'bg-slate-100 text-slate-600'}`}>
              {triageLevel === 'emergency' ? <AlertCircle size={28} /> :
               triageLevel === 'urgent' ? <AlertTriangle size={28} /> :
               triageLevel === 'mild' ? <CheckCircle size={28} /> :
               <Activity size={28} />}
            </div>

            <div>
              <h2 className={`text-xl font-bold capitalize tracking-tight
                  ${triageLevel === 'emergency' ? 'text-red-900' : 
                    triageLevel === 'urgent' ? 'text-orange-900' :
                    triageLevel === 'mild' ? 'text-green-900' :
                    'text-slate-900'}`}>
                {triageLevel === 'emergency' ? 'Emergency Recommendation' :
                 triageLevel === 'urgent' ? 'Medical Attention Advised' :
                 triageLevel === 'mild' ? 'Likely Mild Condition' :
                 'Analysis Complete'}
              </h2>
              <p className={`text-sm font-medium mt-1 opacity-90
                  ${triageLevel === 'emergency' ? 'text-red-800' : 
                    triageLevel === 'urgent' ? 'text-orange-800' :
                    triageLevel === 'mild' ? 'text-green-800' :
                    'text-slate-600'}`}>
                 {triageLevel === 'emergency' ? 'Immediate medical care is recommended.' :
                 triageLevel === 'urgent' ? 'Plan to see a doctor soon for evaluation.' :
                 triageLevel === 'mild' ? 'Self-care may be sufficient, but monitor symptoms.' :
                 'Review the detailed breakdown below.'}
              </p>
            </div>
          </div>

          {/* TTS Controls */}
          {canSpeak && (
            <div className="flex-shrink-0">
               {isSpeaking ? (
                 <button 
                   onClick={handleStop}
                   className="flex items-center space-x-2 px-3 py-1.5 bg-red-100 text-red-700 rounded-lg text-sm font-medium hover:bg-red-200 transition-colors"
                 >
                   <StopCircle size={16} />
                   <span>Stop</span>
                 </button>
               ) : (
                 <button 
                   onClick={handleSpeak}
                   className="flex items-center space-x-2 px-3 py-1.5 bg-white/50 text-slate-700 rounded-lg text-sm font-medium hover:bg-white/80 border border-slate-200/50 transition-colors"
                 >
                   <Volume2 size={16} />
                   <span>Listen to Summary</span>
                 </button>
               )}
            </div>
          )}
        </div>

        {/* Quick Summary Body */}
        <div className="p-5 bg-white/60">
             {/* Topline Text */}
             {summarySnippet && (
                <div className="mb-5">
                    <h3 className="text-xs font-bold uppercase tracking-wider text-slate-500 mb-2 flex items-center">
                        <Sparkles size={14} className="mr-1.5" /> Quick Summary
                    </h3>
                    <p className="text-slate-800 text-sm leading-relaxed font-medium">
                        {summarySnippet}
                    </p>
                </div>
             )}

             {/* Action Bullets */}
             {quickActions.length > 0 && (
                 <div className="bg-white/80 rounded-xl p-4 border border-black/5 shadow-sm">
                     <h4 className="text-xs font-bold uppercase tracking-wider text-slate-500 mb-2 flex items-center">
                         <ArrowRight size={14} className="mr-1.5" /> Recommended Actions
                     </h4>
                     <ul className="space-y-2">
                         {quickActions.map((action, i) => (
                             <li key={i} className="flex items-start text-sm text-slate-700">
                                 <span className={`mt-1.5 mr-2 w-1.5 h-1.5 rounded-full flex-shrink-0 
                                     ${triageLevel === 'emergency' ? 'bg-red-400' : 
                                       triageLevel === 'urgent' ? 'bg-orange-400' : 
                                       'bg-green-400'}`}></span>
                                 {action}
                             </li>
                         ))}
                     </ul>
                 </div>
             )}
        </div>
      </div>

      {/* PDF DOWNLOAD BUTTON */}
      <button 
        onClick={handleDownloadPDF}
        className="w-full flex items-center justify-center space-x-2 py-3 bg-white border border-slate-300 text-slate-700 rounded-xl shadow-sm hover:bg-slate-50 hover:text-teal-600 hover:border-teal-200 transition-all group"
      >
        <FileDown size={18} className="group-hover:scale-110 transition-transform" />
        <span className="font-semibold text-sm">Download Full Report (PDF)</span>
      </button>

      {/* DETAILED SECTIONS ACCORDION */}
      <div className="space-y-3">
        {accordionSections.map((section, idx) => {
          const isExpanded = expandedSections[idx] === true; 

          return (
            <div key={idx} className="bg-white rounded-lg shadow-sm border border-slate-200 overflow-hidden transition-all duration-300 hover:shadow-md">
              <button 
                onClick={() => toggleSection(idx)}
                className="w-full flex items-center justify-between p-4 bg-white hover:bg-slate-50 transition-colors"
              >
                <div className="flex items-center space-x-3">
                  <div className={`p-2 rounded-lg transition-colors ${isExpanded ? 'bg-slate-100 text-teal-600' : 'bg-white text-slate-400 border border-slate-100'}`}>
                    {section.icon}
                  </div>
                  <h3 className="font-semibold text-base text-slate-800 text-left">{section.title}</h3>
                </div>
                <div className={`transform transition-transform duration-300 ${isExpanded ? 'rotate-180' : ''}`}>
                  <ChevronDown className="text-slate-400 w-5 h-5" />
                </div>
              </button>

              {/* Accordion Content */}
              <div 
                className={`grid transition-[grid-template-rows] duration-300 ease-out ${
                  isExpanded ? 'grid-rows-[1fr] opacity-100' : 'grid-rows-[0fr] opacity-0'
                }`}
              >
                <div className="overflow-hidden">
                  <div className="px-5 pb-5 pt-0 border-t border-slate-50 mt-1">
                     <div className="prose prose-sm prose-slate max-w-none mt-4">
                       {renderContent(section.content)}
                     </div>
                  </div>
                </div>
              </div>
            </div>
          );
        })}
      </div>

